const h="/api";function p(n,t){return fetch(`${h}/simulation-snapshots`,{method:"POST",headers:{Authorization:`Bearer ${n}`,"Content-Type":"application/json"},body:JSON.stringify(t)}).then(a=>a.json())}function m(n,t,a,e,s="dynamic",o="week"){const r=new URLSearchParams({createdBy:t,fileName:a,version:e,source:s,dimension:o});return fetch(`${h}/simulation-snapshots/names?${r.toString()}`,{headers:{Authorization:`Bearer ${n}`}}).then(i=>i.json())}function u(n,t,a,e,s,o="dynamic",r="week"){const i=new URLSearchParams({createdBy:t,fileName:a,version:e,snapshotName:s,source:o,dimension:r});return fetch(`${h}/simulation-snapshots?${i.toString()}`,{headers:{Authorization:`Bearer ${n}`}}).then(c=>c.json())}export{m as a,u as g,p as s};
